import React, { useState, useCallback } from 'react';
import { Banana, Loader2, Wand2, RefreshCw, Download, Trash2 } from 'lucide-react';
import { generateBananaImage, generateCreativePrompt } from './services/geminiService';
import { GeneratedImage } from './types';

const App: React.FC = () => {
  const [prompt, setPrompt] = useState<string>('');
  const [loading, setLoading] = useState<boolean>(false);
  const [currentImage, setCurrentImage] = useState<GeneratedImage | null>(null);
  const [history, setHistory] = useState<GeneratedImage[]>([]);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = useCallback(async () => {
    if (!prompt.trim()) return;

    setLoading(true);
    setError(null);
    try {
      // Enhance prompt to ensure it's banana-themed if not explicitly stated, 
      // but trust the user's creative direction mostly.
      const finalPrompt = prompt.toLowerCase().includes('banana') 
        ? prompt 
        : `A banana ${prompt}`;

      const imageBase64 = await generateBananaImage(finalPrompt);

      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        data: imageBase64,
        prompt: finalPrompt,
        timestamp: Date.now(),
      };

      setCurrentImage(newImage);
      setHistory(prev => [newImage, ...prev]);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to generate banana. The peel was too slippery.');
    } finally {
      setLoading(false);
    }
  }, [prompt]);

  const handleSurpriseMe = useCallback(async () => {
    setLoading(true);
    setError(null);
    setPrompt("Thinking of a peeled idea...");
    try {
      const creativePrompt = await generateCreativePrompt();
      setPrompt(creativePrompt);

      // Auto-generate after getting the prompt
      const imageBase64 = await generateBananaImage(creativePrompt);
      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        data: imageBase64,
        prompt: creativePrompt,
        timestamp: Date.now(),
      };

      setCurrentImage(newImage);
      setHistory(prev => [newImage, ...prev]);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to dream of bananas.');
    } finally {
      setLoading(false);
    }
  }, []);

  const handleDownload = (dataUrl: string, filename: string) => {
    const link = document.createElement('a');
    link.href = dataUrl;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleClearHistory = () => {
    setHistory([]);
    setCurrentImage(null);
  };

  return (
    <div className="min-h-screen flex flex-col font-sans">
      {/* Header */}
      <header className="bg-banana-500 text-brown-900 p-6 shadow-lg sticky top-0 z-50">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <Banana size={40} className="text-brown-900 animate-wiggle" />
            <h1 className="text-3xl font-black tracking-tight">BANANA GEN</h1>
          </div>
          <div className="text-sm font-bold bg-banana-300 px-3 py-1 rounded-full border-2 border-brown-900 shadow-sm hidden sm:block">
            Powered by Gemini
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow max-w-4xl mx-auto w-full p-4 sm:p-6 space-y-8">

        {/* Controls Section */}
        <section className="bg-white rounded-3xl p-6 shadow-xl border-4 border-banana-400">
          <div className="flex flex-col space-y-4">
            <label className="text-brown-900 font-bold text-lg">
              Describe your banana vision:
            </label>
            <div className="flex flex-col sm:flex-row gap-3">
              <input 
                type="text" 
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                placeholder="e.g., A cyberpunk banana surfing on a data stream..."
                className="flex-grow p-4 rounded-xl border-2 border-banana-300 focus:border-banana-600 focus:ring-4 focus:ring-banana-200 transition-all outline-none text-lg text-brown-900 placeholder-banana-700/50"
                onKeyDown={(e) => e.key === 'Enter' && handleGenerate()}
              />
              <button 
                onClick={handleGenerate}
                disabled={loading || !prompt}
                className="bg-banana-500 hover:bg-banana-400 disabled:opacity-50 disabled:cursor-not-allowed text-brown-900 font-bold py-4 px-8 rounded-xl shadow-[0_4px_0_rgb(249,168,37)] active:shadow-none active:translate-y-[4px] transition-all flex items-center justify-center gap-2 min-w-[160px]"
              >
                {loading ? <Loader2 className="animate-spin" /> : <Wand2 />}
                GENERATE
              </button>
            </div>

            <div className="flex justify-between items-center">
               <button 
                onClick={handleSurpriseMe}
                disabled={loading}
                className="text-banana-800 hover:text-banana-900 font-bold text-sm flex items-center gap-2 hover:underline decoration-2 underline-offset-4"
              >
                <RefreshCw size={16} className={loading ? 'animate-spin' : ''} />
                Surprise me with a random banana
              </button>
            </div>

            {error && (
              <div className="bg-red-100 text-red-800 p-4 rounded-xl border border-red-200">
                <strong>Oops!</strong> {error}
              </div>
            )}
          </div>
        </section>

