        {/* History Gallery */}
        {history.length > 0 && (
          <section className="pt-8 border-t-4 border-banana-200 border-dashed">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-black text-brown-900 flex items-center gap-2">
                <Banana className="text-banana-600" /> 
                The Bunch (History)
              </h2>
              <button 
                onClick={handleClearHistory}
                className="text-red-500 hover:text-red-700 flex items-center gap-1 text-sm font-bold"
              >
                <Trash2 size={16} /> Clear Bunch
              </button>
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4">
              {history.map((img) => (
                <div 
                  key={img.id} 
                  onClick={() => setCurrentImage(img)}
                  className={`cursor-pointer rounded-xl overflow-hidden border-2 transition-all hover:scale-105 active:scale-95 ${currentImage?.id === img.id ? 'border-banana-600 ring-2 ring-banana-300 shadow-lg' : 'border-transparent hover:border-banana-300'}`}
