import React, { useState, useCallback, useRef } from 'react';
import { Banana, Loader2, Wand2, RefreshCw, Download, Trash2, Upload, X, Image as ImageIcon } from 'lucide-react';
import { generateBananaImage, generateCreativePrompt } from './services/geminiService';
import { GeneratedImage } from './types';

interface UploadedImage {
  preview: string; // Full data URL for display
  data: string;    // Base64 string for API
  mimeType: string;
}

const App: React.FC = () => {
  const [prompt, setPrompt] = useState<string>('');
  const [loading, setLoading] = useState<boolean>(false);
  const [currentImage, setCurrentImage] = useState<GeneratedImage | null>(null);
  const [history, setHistory] = useState<GeneratedImage[]>([]);
  const [error, setError] = useState<string | null>(null);

  const [uploadedImage, setUploadedImage] = useState<UploadedImage | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      // Check file type
      if (!file.type.startsWith('image/')) {
        setError("Please upload a valid image file (PNG, JPEG, etc).");
        return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        const result = reader.result as string;
        // Regex to extract base64 data and mime type: data:image/png;base64,....
        const matches = result.match(/^data:(.+);base64,(.+)$/);
        if (matches) {
          setUploadedImage({
            preview: result,
            mimeType: matches[1],
            data: matches[2]
          });
          setError(null); // Clear previous errors
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const clearUploadedImage = () => {
    setUploadedImage(null);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  const handleGenerate = useCallback(async () => {
    if (!prompt.trim()) return;

    setLoading(true);
    setError(null);
    try {
      // Enhance prompt to ensure it's banana-themed if not explicitly stated, 
      // but trust the user's creative direction mostly.
      const finalPrompt = prompt.toLowerCase().includes('banana') 
        ? prompt 
        : `A banana ${prompt}`;

      const referenceImage = uploadedImage ? { 
        data: uploadedImage.data, 
        mimeType: uploadedImage.mimeType 
      } : undefined;

      const imageBase64 = await generateBananaImage(finalPrompt, referenceImage);

      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        data: imageBase64,
        prompt: finalPrompt,
        timestamp: Date.now(),
      };

      setCurrentImage(newImage);
      setHistory(prev => [newImage, ...prev]);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to generate banana. The peel was too slippery.');
    } finally {
      setLoading(false);
    }
  }, [prompt, uploadedImage]);

  const handleSurpriseMe = useCallback(async () => {
    setLoading(true);
    setError(null);
    setPrompt("Thinking of a peeled idea...");
    try {
      const creativePrompt = await generateCreativePrompt();
      setPrompt(creativePrompt);

      // Auto-generate after getting the prompt, ignoring uploaded image for pure surprise
      const imageBase64 = await generateBananaImage(creativePrompt);
      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        data: imageBase64,
        prompt: creativePrompt,
        timestamp: Date.now(),
      };

      setCurrentImage(newImage);
      setHistory(prev => [newImage, ...prev]);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to dream of bananas.');
    } finally {
      setLoading(false);
    }
  }, []);

  const handleDownload = (dataUrl: string, filename: string) => {
    const link = document.createElement('a');
    link.href = dataUrl;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleClearHistory = () => {
    setHistory([]);
    setCurrentImage(null);
  };

  return (
    <div className="min-h-screen flex flex-col font-sans">
      {/* Header */}
      <header className="bg-banana-500 text-brown-900 p-6 shadow-lg sticky top-0 z-50">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <Banana size={40} className="text-brown-900 animate-wiggle" />
            <h1 className="text-3xl font-black tracking-tight">BANANA GEN</h1>
          </div>
          <div className="text-sm font-bold bg-banana-300 px-3 py-1 rounded-full border-2 border-brown-900 shadow-sm hidden sm:block">
            Powered by Gemini
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow max-w-4xl mx-auto w-full p-4 sm:p-6 space-y-8">

        {/* Controls Section */}
        <section className="bg-white rounded-3xl p-6 shadow-xl border-4 border-banana-400">
          <div className="flex flex-col space-y-4">

            <label className="text-brown-900 font-bold text-lg">
              1. Upload Reference Image (Optional):
            </label>

            {/* Image Upload Area */}
            {!uploadedImage ? (
              <div 
                onClick={() => fileInputRef.current?.click()}
                className="border-2 border-dashed border-banana-600 rounded-xl p-6 flex flex-col items-center justify-center cursor-pointer hover:bg-banana-50 transition-colors gap-2 text-banana-800"
              >
                <ImageIcon size={32} />
                <span className="font-semibold">Click to upload an image to edit/transform</span>
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  onChange={handleImageUpload} 
                  accept="image/*" 
                  className="hidden" 
                />
              </div>
            ) : (
              <div className="relative inline-block w-fit rounded-xl overflow-hidden border-2 border-banana-600 shadow-sm">
                 <img 
                   src={uploadedImage.preview} 
                   alt="Uploaded reference" 
                   className="h-32 w-auto object-cover"
                 />
                 <button 
                   onClick={clearUploadedImage}
                   className="absolute top-1 right-1 bg-red-500 text-white p-1 rounded-full hover:bg-red-600 transition-colors shadow-sm"
                   title="Remove image"
                 >
                   <X size={16} />
