              </button>
            </div>

            {error && (
              <div className="bg-red-100 text-red-800 p-4 rounded-xl border border-red-200">
                <strong>Oops!</strong> {error}
              </div>
            )}
          </div>
        </section>

        {/* Display Section */}
        {currentImage && (
          <section className="animate-in fade-in zoom-in duration-500">
            <div className="bg-white p-4 rounded-3xl shadow-2xl border-4 border-banana-500 rotate-1 hover:rotate-0 transition-transform duration-300">
              <div className="aspect-square w-full rounded-2xl overflow-hidden bg-banana-50 relative group">
                <img 
